var e=JSON.parse(`[{"id":"L8_1","type":"dialog","speaker":"PHOTO_EXTRA_NULL_A","text":{"KOREA":"와일러 씨! 이번에 가석방이 결정되었다고 들었는데 한 마디 해주시죠!","JPN":"ワイラーさん！　今度仮釈放が認められたと聞きましたが、一言お願いします！","ENG":"Mr. Wyler! Your parole was approved this time. Care to comment on it?","TWN":"瓦勒！聽說法院已經裁准你的保釋申請，你有什麼話想說嗎？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L9_1","type":"dialog","speaker":"PHOTO_EXTRA_NULL_B","text":{"KOREA":"건틀렛 살인마라는 별명을 어떻게 생각하십니까!","JPN":"ガントレットの殺人鬼という呼び名についてどう思いますか！","ENG":"What do you think about your nickname, Gauntlet Murderer?","TWN":"對於有人說你是聖鎧殺人魔，你個人是怎麼想的？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PHOTO_EXTRA_NULL_A","text":{"KOREA":"유가족들에게 하실 말씀 없습니까? 죄책감 같은 건 안느끼시나요?","JPN":"遺族に伝えることはありませんか？　罪の意識については？","ENG":"Do you have anything to say to the bereaved families? Do you not feel any guilt?!","TWN":"你有話要對受害者的家屬說嗎？你一點罪惡感都沒有嗎？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PHOTO_EXTRA_NULL_B","text":{"KOREA":"조사해보니 와일러 씨는 현재 어떤 여성에게 접근금지 명령을 받은 상태라고 하던데요?","JPN":"調べによると、現在、ワイラーさんにはある女性への接近禁止命令が出されているらしいですね？","ENG":"After some investigation, I heard that some woman put a restraining order on you. Is that true?","TWN":"我們收到消息，聽說有某位女性申請保護令，禁止你接近她？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PHOTO_EXTRA_NULL_B","text":{"KOREA":"이번 사건과의 연관성에 대하여…….","JPN":"今度の事件との関連性について……","ENG":"Does that have anything to do with this case–","TWN":"是和這次的事件有關係嗎……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"……뭐?","JPN":"……は？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그만, 의뢰인. 약속했을 텐데요?","JPN":"そこまで、依頼人。約束したはずです。","ENG":"Client, enough. You promised.","TWN":"住口，委託人，我們說好的。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"PHOTO_EXTRA_NULL_A","text":{"KOREA":"조니 앤 멜로니는 이 사건에 대해 어떤 입장입니까?","JPN":"ジョニー＆メロニーは、この事件についてどのような立場なのでしょうか？","ENG":"What does Jonie & Melonie have to say about this case?","TWN":"強尼＆梅蘭妮在這次事件中的立場是什麼呢？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"PHOTO_EXTRA_NULL_A","text":{"KOREA":"악질 범죄자를 옹호하는 모습이 일류 로펌이라는 이미지에 도움되진 않을 텐데요?","JPN":"悪質な犯罪者を擁護することは、一流ローファームのイメージにプラスとならないはずですが？","ENG":"Won't a top-notch law firm have its image tainted for defending a vicious criminal?","TWN":"替罪犯開脫對一流法律事務所的形象應該沒有幫助吧？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"저희 의뢰인은 현재 거듭된 재판으로 피로가 쌓인 상태입니다.","JPN":"私の依頼人は現在、度重なる裁判で疲労が溜まっている状態です。","ENG":"My client is currently exhausted from the repeated trials.","TWN":"我的委託人現在因為一連串的審理而非常疲憊。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"질문은 받지 않겠습니다. 자세한 재판 내용은 법원에 문의하시죠.","JPN":"質問はご遠慮ください。詳しい裁判の内容は、裁判所宛てにお問い合わせください。","ENG":"We are not taking questions at the moment. Please ask the court for details about the case.","TWN":"我們不接受任何提問，關於裁決內容的部分請詢問法院。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"차를 대기시켜 놓았습니다. 타시죠, 의뢰인.","JPN":"車を待機させておきました。どうぞ、依頼人。","ENG":"We have a car ready for you. Please get in, client.","TWN":"我已經準備好車了，上車吧，委託人。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"역시 일처리가 확실하네. 비싼 수임료 값을 하는데?","JPN":"さすが仕事が早いわね。ペイが高いだけはあるわ。","ENG":"You get the job done quick. No wonder you're so expensive.","TWN":"果然是辦事很牢靠，不枉費我付那麼多律師費呢？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"재판은 증거만이 전부죠.","JPN":"裁判は証拠がすべてです。","ENG":"In trials, evidence is everything.","TWN":"法院講求的是證據。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"검찰 측의 주장은 모두 정황 증거에 근거한 것일 뿐.","JPN":"検察側の主張は、全部状況証拠でしかありません。","ENG":"The prosecution's argument was all based on contextual evidence.","TWN":"檢察官提出的主張都只是推測而已，並無法舉證。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"직접적인 증거가 없는 한, 이 사건에서 의도적으로 살인이 자행되었다는 걸 검찰이 입증할 방법은 없어요.","JPN":"直接的な証拠がない限り、この事件で意図的に殺人が行われたということを検察が立証する方法はありません。","ENG":"Unless there is direct evidence, there is no way for them to prove that the alleged murder was intentionally committed in this case.","TWN":"在沒有直接證據的情況下，檢察官無法證明本案為蓄意殺人。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그리고 그 증거는 당신이 모두 처리했죠. 다음은 그저 지리멸렬한 말싸움일 뿐입니다.","JPN":"そして、その証拠はあなたがすべて片付けた。残っているのはただ、支離滅裂な口喧嘩だけです。","ENG":"And you had already taken care of the evidence. What comes next is merely a pathetic verbal brawl.","TWN":"再說，所謂的證據都被你銷毀了吧？接下來就只剩冗長的庭審過程。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"뭘 그렇게 말을 어렵게 해, 람다.","JPN":"小難しげに言うけどね、ラムダ。","ENG":"Why make it sound so difficult, Lamda?","TWN":"說這麼多要幹嘛，蘭達？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"결국 배심원들을 구워삶았다는 뜻이잖아. 사실상 종신형 확정이나 마찬가지였다고 하는데.","JPN":"結局のところ、陪審員を丸め込んだってことじゃない。事実上、終身刑確定も同然だったらしいけど。","ENG":"Simply put, you coaxed the jury, didn't you? They said that he would surely receive a life sentence.","TWN":"總之就是他原本是要判終身監禁的，但你說服了陪審團對吧？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"과실치사도 죄는 죄입니다.","JPN":"過失致死も罪は罪です。","ENG":"Involuntary manslaughter is still a crime.","TWN":"過失致死罪也是罪，"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"형기가 만료될 때까지는 조용하게 지내게 하시죠.","JPN":"刑期が満了するまでは、大人しく過ごすようにしてください。","ENG":"I advise you to have him lay low until his sentence expires.","TWN":"在刑期結束前，勸你不要太高調。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"특히 남들 앞에서 쓸데없는 소리 못하게 하시고요.","JPN":"特に、人前で余計なことを言わないように。","ENG":"Furthermore, please tell him to refrain from saying any nonsense in front of other people.","TWN":"尤其是不要在別人面前說那些有的沒的。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"알았어~ 알았어~ 람다는 잔소리도 많다니깐?","JPN":"わかった～わかった～ラムダったら口うるさいんだから。","ENG":"All right, all right. Sheesh, you and your nagging.","TWN":"好啦～好啦～蘭達你也很囉唆欸？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"……그럼. 전 볼일이 있어서 이만.","JPN":"……それでは。私は用事がありますので、失礼。","ENG":"...Well then. I have somewhere else to be.","TWN":"……那我還有事，先失陪。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"……마음에 안 드는 여자야. 낯짝도, 말투도 건방져.","JPN":"……気に食わねぇ女だ。面も口調も調子に乗りやがって。","ENG":"...I don't like her. She is as arrogant as her tone.","TWN":"……我不喜歡她，瞧她那副不可一世的嘴臉和囂張的語氣。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"그래서? 왜 비싼 변호사까지 써 가면서 나를 도와준 거지, 챔피언?","JPN":"それで？　なんで高給取りの弁護士まで使って俺を助けたんだ？　チャンピオン。","ENG":"So, champion. Why are you helping me, going as far as hiring an expensive lawyer?","TWN":"說吧？為什麼要花大錢請律師保我出來，冠軍？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"내 플레이가 마음에 들기라도 했나?","JPN":"俺のプレイが気に入ったのか？","ENG":"Did my feats during the last Gauntlet inspire you?","TWN":"難道你是喜歡我的比賽表現？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"흐음~ 뭐, 대충 그렇다고 할까? 난 예술가를 선호하거든.","JPN":"ふーん。まあ、そういうことにしておこうかしら。私は芸術家が好きなの。","ENG":"Hmm... Well, let's just say that they did. You see, I'm a fan of artists.","TWN":"嗯～意思差不多？我喜歡藝術家。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그리고 예술가들이 꿈을 이룰 수 있도록 후원해 주는 것도 좋아하는 편이야.","JPN":"芸術家たちが夢を叶えられるように後押しすることもね。","ENG":"Also, I'm a philanthropist who supports those artists to achieve their dreams.","TWN":"也喜歡支持藝術家完成他們的夢想。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"이 영상은……?","JPN":"この映像は……？","ENG":"What's that on the screen...?","TWN":"這支影片是……？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"경기 끝났습니다─! 본선 1경기의 승자는!","JPN":"試合、終了です─！　本戦第1試合の勝者は！","ENG":"Game set! The winner of the first elimination round is!","TWN":"比賽結束─！第一回合決賽的優勝隊伍是！"},"stage":{"bg":"CCN_SHIP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"대담하게도 함선을 미끼로 단숨에 경기를 끝내버린 카나리아 스쿼드─!","JPN":"大胆にも艦船をおとりに、一気に試合を終わらせたカナリア・スクワッド─！","ENG":"The daring team that used their aircraft as bait and ended the match in a flash! Canary Squad!","TWN":"非常大膽地以艦船當作誘餌，瞬間結束比賽的金絲雀小隊─！"},"stage":{"bg":"CCN_SHIP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"샤레이드의 문제아들이 또다시 사고를 치고 말았다!","JPN":"シャレードの問題児がまたやっちゃった！","ENG":"Charade's troublemakers have struck again!","TWN":"查雷德的問題兒童又闖禍囉！"},"stage":{"bg":"CCN_SHIP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"주문한 치킨이 채 도착하기도 전에 이겨버리는 압도적인 경기력!","JPN":"デリバリーのチキンが到着する前に勝っちゃう圧倒的な競技力！","ENG":"An overwhelming performance! Finishing the match before the pizza you ordered arrives!","TWN":"點的外送都還沒到，就以卓越的作戰能力取得壓倒性的勝利！"},"stage":{"bg":"CCN_SHIP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"자! 그럼~ 오늘 경기의 하이라이트! 퍼스트 키스의 순간을 다시 한번 감상해 보자구~?","JPN":"さて！　それじゃ～今日の試合のハイライト！　ファーストキスの瞬間をもう一度どうぞ～！","ENG":"Okay! Now, for the highlights of today's match! Let's watch the first kiss scene again!","TWN":"接下來！就讓我們再次回顧今天的精彩畫面─艦船撞上的瞬間！"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"함선의 움직임, 테크닉, 반응 속도…… 상당한 실력의 스태프로군.","JPN":"艦船の動き、テクニック、反応速度……相当な実力のあるスタッフだな。","ENG":"The ship's movement, technique, and reaction speed... That staff member has some incredible skills.","TWN":"從艦船的移動、控制技巧、反應速度看來……駕駛員的能力非常出色。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"이 정도 실력 좋은 스태프는 샤레이드에서도 몇 손가락 안에 손꼽을 수 있지.","JPN":"これほど実力のあるスタッフは、シャレードでも数少ない。","ENG":"With those skills, I would say they're in the top 5 in Charade.","TWN":"能力如此出色的駕駛員，在查雷德屈指可數。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"……아아, 그래. 맞아. 스키너야.","JPN":"……ああ、そう。そうだ。スキナーだ。","ENG":"...Ahh, yes. That's Skinner.","TWN":"……嗯嗯，沒錯，就是史金納。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그 여자, 네가 재판을 받는 동안 질 나쁜 길거리 애들이랑 어울려 다닌다고 하던데.","JPN":"あの女、あなたが裁判を受けてる間に質の悪い子たちと付き合ってるらしいの。","ENG":"That girl–I heard she was hanging with the wrong crowd while you were on trial.","TWN":"聽說在你被抓起來的這段時間，她和街頭小混混混在一起。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"그럴 수가…… 그러면 안 되지.","JPN":"そんな……そりゃいただけねぇな。","ENG":"That can't be... I won't allow it.","TWN":"怎麼會……這怎麼可以。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"스키너는 마음씨가 너무 좋아서 탈이야. 옆에 달라붙어 찝적대는 놈들도 감싸줬으니까.","JPN":"スキナーは心根が優しすぎるんだ。そばにくっついてはちょっかいを出す奴らも庇っていたからな。","ENG":"Skinner has too generous a heart. She even protects those who keep hitting on her.","TWN":"史金納就是心地太善良了，連身邊的蒼蠅她都很照顧。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"그녀에게는 용기와 결단이 필요해. 하지만 그건 그 고운 마음씨에 흠집을 내는 일이야.","JPN":"彼女には勇気と決断が必要だ。だが、それはあの優しい心を傷つけちまう。","ENG":"She needs courage and decisiveness. But those will only break her kind heart.","TWN":"她需要的是勇氣和魄力，但這會讓她美麗的心留下瑕疵。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"맞아. 그래서였어. 내가 스키너 대신에 놈들을 심판해 준 거야.","JPN":"そうだ。だからなんだ。俺がスキナーに代わって奴らを審判してやったのさ。","ENG":"Yeah. That's why I did it. I brought judgment to those scums on her behalf.","TWN":"沒錯，就是因為這樣，所以我才會代替史金納審判那些傢伙。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"더러운 욕정으로 접근하는 놈들, 이용해 먹을 생각만 가득한 년들…….","JPN":"汚い色欲で近づく男ども、利用する気満々の女ども……","ENG":"Those filthy, despicable bastards full of lust and manipulative bitches that approach her just to use her...","TWN":"那些不懷好意親近她的男人，還有想利用她的女人……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그래, 그래. 우리 어린이. 지금은 조금만 참아.","JPN":"そう、そう。いい子ね。今は少しだけ我慢しなさい。","ENG":"Yes, yes, my child. Just be patient.","TWN":"好了好了，你再忍耐一下。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"금방 다시 만나게 해줄 테니까.","JPN":"すぐまた会えるようにしてあげるから。","ENG":"I'll let you see her soon enough.","TWN":"我很快就會讓你們復合的。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"……확실히 너는 이 도시의 멍청한 녀석들과 다르군.","JPN":"……確かにお前はこの街のアホどもとは違うな。","ENG":"...You're certainly different from the idiots in this city.","TWN":"……你確實和這座城市裡的其他蠢蛋不太一樣。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"물론이지, 살인마 씨.","JPN":"もちろんよ、殺人鬼さん。","ENG":"Of course I am, Mr. Murderer.","TWN":"那當然囉，殺人魔先生。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"난 너 같은 녀석의 손끝에서도 걸작이 태어날 수 있다고 믿는 편이거든.","JPN":"私はあなたみたいな人の手からも傑作は生まれると信じてるの。","ENG":"I believe that even someone like you can create a masterpiece.","TWN":"我相信從你這種人的指尖上也能創造出傑作的。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};